  16: { name: "Dovednosti", nameEn: "Skills", iChing: "Nadšení", hexagram: "☳☷", center: "Hrdlo", circuit: "Kolektivní", theme: "Mistrovství skrze praxi", themeEn: "Mastery through practice", description: "Brána Dovedností je o nadšení pro rozvíjení mistrovství skrze praxi a opakování. Lidé s touto branou jsou poháněni zdokonalovat své dovednosti a sdílet svou odbornost.", descriptionEn: "Gate 16 is about enthusiasm for developing mastery through practice and repetition. People with this gate are driven to perfect their skills and share their expertise.", giftKeyword: "Všestrannost", giftKeywordEn: "Versatility", shadowKeyword: "Lhostejnost", shadowKeywordEn: "Indifference" },
  17: { name: "Názory", nameEn: "Opinions", iChing: "Následování", hexagram: "☱☳", center: "Ajna", circuit: "Kolektivní", theme: "Logické názory", themeEn: "Logical opinions", description: "Brána Názorů je o formování a sdílení logických názorů. Lidé s touto branou mají přirozenou schopnost vidět vzorce a formovat názory o tom, jak by věci měly fungovat.", descriptionEn: "Gate 17 is about forming and sharing logical opinions. People with this gate have a natural ability to see patterns and form opinions about how things should work.", giftKeyword: "Dalekovidnost", giftKeywordEn: "Far-sightedness", shadowKeyword: "Dogmatismus", shadowKeywordEn: "Dogmatism" },
