  19: { name: "Touha", nameEn: "Wanting", iChing: "Přiblížení", hexagram: "☷☱", center: "Kořen", circuit: "Kmenový", theme: "Citlivost k potřebám", themeEn: "Sensitivity to needs", description: "Brána Touhy je o citlivosti k základním potřebám komunity. Lidé s touto branou jsou hluboce naladěni na to, co ostatní potřebují a chtějí.", descriptionEn: "Gate 19 is about sensitivity to the fundamental needs of the community. People with this gate are deeply attuned to what others need and want.", giftKeyword: "Citlivost", giftKeywordEn: "Sensitivity", shadowKeyword: "Závislost", shadowKeywordEn: "Co-dependence" },
  20: { name: "Přítomnost", nameEn: "The Now", iChing: "Rozjímání", hexagram: "☴☷", center: "Hrdlo", circuit: "Individuální", theme: "Vědomí přítomného okamžiku", themeEn: "Awareness of the present moment", description: "Brána Přítomnosti je o síle vědomí přítomného okamžiku. Lidé s touto branou mají přirozenou schopnost být plně přítomni a vyjadřovat, co se děje v daném okamžiku.", descriptionEn: "Gate 20 is about the power of present-moment awareness. People with this gate have a natural ability to be fully present and express what is happening in the moment.", giftKeyword: "Sebejistota", giftKeywordEn: "Self-assurance", shadowKeyword: "Povrchnost", shadowKeywordEn: "Superficiality" },
