  22: { name: "Otevřenost", nameEn: "Openness", iChing: "Elegance", hexagram: "☶☲", center: "Solární plexus", circuit: "Individuální", theme: "Emocionální otevřenost a elegance", themeEn: "Emotional openness and grace", description: "Brána Otevřenosti je o emocionální eleganci a schopnosti naslouchat s otevřeným srdcem. Lidé s touto branou nesou hlubokou emocionální citlivost, která může ve správný čas dotknout a transformovat ostatní.", descriptionEn: "Gate 22 is about emotional grace and the ability to listen with an open heart. People with this gate carry a deep emotional sensitivity that can touch and transform others at the right time.", giftKeyword: "Laskavost", giftKeywordEn: "Graciousness", shadowKeyword: "Bezectnost", shadowKeywordEn: "Dishonor" },
  23: { name: "Asimilace", nameEn: "Assimilation", iChing: "Rozpad", hexagram: "☶☷", center: "Hrdlo", circuit: "Individuální", theme: "Vyjádření individuálního poznání", themeEn: "Expression of individual knowing", description: "Brána Asimilace je o schopnosti překládat individuální poznatky do jazyka, kterému ostatní rozumí. Lidé s touto branou jsou zde, aby sdíleli jedinečné perspektivy, které mohou zpočátku znít zvláštně, ale nesou hlubokou pravdu.", descriptionEn: "Gate 23 is about the ability to translate individual insights into language others can understand. People with this gate are here to share unique perspectives that may initially sound strange but carry deep truth.", giftKeyword: "Jednoduchost", giftKeywordEn: "Simplicity", shadowKeyword: "Složitost", shadowKeywordEn: "Complexity" },
  24: { name: "Racionalizace", nameEn: "Rationalization", iChing: "Návrat", hexagram: "☷☳", center: "Ajna", circuit: "Individuální", theme: "Mentální přezkum a rekoncepce", themeEn: "Mental review and reconceptualization", description: "Brána Racionalizace je o mentálním procesu přezkoumávání a překonceptualizace myšlenek. Lidé s touto branou prožívají neustálou mentální smyčku přehodnocování a zdokonalování svého porozumění.", descriptionEn: "Gate 24 is about the mental process of reviewing and reconceptualizing thoughts. People with this gate experience a constant mental loop of reassessing and refining their understanding.", giftKeyword: "Vynalézavost", giftKeywordEn: "Inventiveness", shadowKeyword: "Závislost", shadowKeywordEn: "Addiction" },
  25: { name: "Nevinnost", nameEn: "Innocence", iChing: "Nevinnost", hexagram: "☰☳", center: "G", circuit: "Individuální", theme: "Univerzální láska a duch", themeEn: "Universal love and spirit", description: "Brána Nevinnosti je o duchu univerzální lásky a přijetí. Lidé s touto branou nesou čistou, nevinnou energii, která je spojuje s božským. Jsou zde, aby milovali bezpodmínečně.", descriptionEn: "Gate 25 is about the spirit of universal love and acceptance. People with this gate carry a pure, innocent energy that connects them to the divine. They are here to love unconditionally.", giftKeyword: "Přijetí", giftKeywordEn: "Acceptance", shadowKeyword: "Omezení", shadowKeywordEn: "Constriction" },
  26: { name: "Šibal", nameEn: "The Trickster", iChing: "Velká zkrocující síla", hexagram: "☶☰", center: "Srdce", circuit: "Kmenový", theme: "Ego a obchodní talent", themeEn: "Ego and business talent", description: "Brána Šibala je o síle přesvědčování a schopnosti prodávat myšlenky, produkty nebo vize. Lidé s touto branou mají přirozený talent pro marketing a přesvědčování ostatních o hodnotě toho, co nabízejí.", descriptionEn: "Gate 26 is about the power of persuasion and the ability to sell ideas, products, or visions. People with this gate have a natural talent for marketing and convincing others of the value of what they offer.", giftKeyword: "Umnost", giftKeywordEn: "Artfulness", shadowKeyword: "Pýcha", shadowKeywordEn: "Pride" },
  27: { name: "Výživa", nameEn: "Caring", iChing: "Poskytování výživy", hexagram: "☶☳", center: "Sakrální", circuit: "Kmenový", theme: "Péče a výživa", themeEn: "Care and nourishment", description: "Brána Výživy je o pečující energii, která živí a udržuje ostatní. Lidé s touto branou mají hlubokou touhu pečovat o ty kolem sebe. Je to energie pečovatele a poskytovatele.", descriptionEn: "Gate 27 is about the nurturing energy that feeds and sustains others. People with this gate have a deep desire to care for those around them. This is the energy of the caretaker and provider.", giftKeyword: "Nezištnost", giftKeywordEn: "Altruism", shadowKeyword: "Sobeckost", shadowKeywordEn: "Selfishness" },
